package main

import "math"

func solve(n int64, edges [][]int64) int64 {
    nInt := int(n)
    if nInt <= 0 {
        return 0
    }
    graph := make([][][3]int64, nInt)
    for i := range graph {
        graph[i] = make([][3]int64, 0)
    }
    for _, e := range edges {
        u := int(e[0])
        v := int(e[1])
        s := e[2]
        end := e[3]
        graph[u] = append(graph[u], [3]int64{int64(v), s, end})
    }

    dist := make([]int64, nInt)
    for i := range dist {
        dist[i] = math.MaxInt64
    }
    dist[0] = 0

    pq := make([][2]int64, 0)

    push := func(time int64, node int) {
        pq = append(pq, [2]int64{time, int64(node)})
        i := len(pq) - 1
        for i > 0 {
            parent := (i - 1) / 2
            if pq[parent][0] <= pq[i][0] {
                break
            }
            pq[parent], pq[i] = pq[i], pq[parent]
            i = parent
        }
    }

    pop := func() (time int64, node int) {
        top := pq[0]
        last := len(pq) - 1
        pq[0] = pq[last]
        pq = pq[:last]
        i := 0
        for {
            left := 2*i + 1
            right := 2*i + 2
            smallest := i
            if left < len(pq) && pq[left][0] < pq[smallest][0] {
                smallest = left
            }
            if right < len(pq) && pq[right][0] < pq[smallest][0] {
                smallest = right
            }
            if smallest == i {
                break
            }
            pq[i], pq[smallest] = pq[smallest], pq[i]
            i = smallest
        }
        return top[0], int(top[1])
    }

    push(0, 0)
    for len(pq) > 0 {
        t, u := pop()
        if t != dist[u] {
            continue
        }
        for _, edge := range graph[u] {
            to := int(edge[0])
            s := edge[1]
            e := edge[2]
            if t > e {
                continue
            }
            candidate := t
            if candidate < s {
                candidate = s
            }
            candidate += 1
            if candidate < dist[to] {
                dist[to] = candidate
                push(candidate, to)
            }
        }
    }

    if dist[nInt-1] == math.MaxInt64 {
        return -1
    }
    return dist[nInt-1]
}
