use std::collections::BinaryHeap;
use std::cmp::Reverse;

func solve(n: Int64, edges: Array<Array<Int64>>) -> Int64 {
    let n_node = n.to_i64() as usize;
    if n_node == 0 {
        return 0;
    }
    let mut dist: Vec<i64> = vec![i64::MAX; n_node];
    dist[0] = 0;

    let mut graph: Vec<Vec<(usize, i64, i64)>> = vec![vec![]; n_node];
