        let s = edge.get(2).to_i64();
        let e = edge.get(3).to_i64();
        graph[u].push((v, s, e));
    }

    let mut heap: BinaryHeap<Reverse<(i64, usize)>> = BinaryHeap::new();
    heap.push(Reverse((0, 0)));

    while let Some(Reverse((t, u))) = heap.pop() {
        if t != dist[u] {
            continue;
        }
        if u == n_node - 1 {
            return t;
        }
        for (v, s, e) in graph[u].iter().copied() {
            let w = if t > s { t } else { s };
            if w <= e {
                let nt = w + 1;
                if nt < dist[v] {
                    dist[v] = nt;
                    heap.push(Reverse((nt, v)));
                }
            }
        }
    }

    -1
}
